import React from 'react';

function DeviceMockups({ screenshots = {} }) {
  const {
    laptop = '/images/dashboard-screenshot.png',
    phone = '/images/app-screenshot.png',
    tablet = '/images/tablet-screenshot.png'
  } = screenshots;

  return (
    <div className="relative w-full h-full flex items-center justify-center scale-75 lg:scale-90">
      {/* Tablet - background left */}
      <div className="absolute -left-10 -top-5 z-0 transform -rotate-6">
        <div className="w-[120px] h-[160px] bg-gradient-to-br from-orange-400 to-red-500 rounded-2xl p-2 shadow-xl opacity-90">
          <div className="w-full h-full bg-gradient-to-br from-orange-300 to-pink-400 rounded-xl flex items-center justify-center">
            <span className="text-white/70 text-xs">Tablet</span>
          </div>
        </div>
      </div>

      {/* Laptop - center main */}
      <div className="relative z-10">
        <div className="w-[300px] h-[190px] bg-gray-900 rounded-t-xl p-2 shadow-2xl">
          <div className="w-full h-full bg-gradient-to-br from-blue-600 to-purple-600 rounded-lg flex items-center justify-center">
            <span className="text-white/80 text-sm">Dashboard Preview</span>
          </div>
        </div>
        <div className="w-[330px] h-3 bg-gradient-to-b from-gray-700 to-gray-800 rounded-b-xl mx-auto relative -left-4"></div>
        <div className="w-[360px] h-2 bg-gray-800 rounded-b-lg mx-auto relative -left-7 shadow-xl"></div>
      </div>

      {/* Phone - right side */}
      <div className="absolute -right-5 top-10 z-20">
        <div className="w-[80px] h-[160px] bg-gray-900 rounded-[1.5rem] p-1.5 shadow-2xl border-2 border-emerald-500">
          <div className="absolute top-2 left-1/2 transform -translate-x-1/2 w-8 h-2 bg-black rounded-full z-10"></div>
          <div className="w-full h-full bg-gradient-to-br from-emerald-400 to-cyan-500 rounded-[1.2rem] flex items-center justify-center">
            <span className="text-white/80 text-[10px]">Mobile App</span>
          </div>
        </div>
      </div>

      {/* Glow effects */}
      <div className="absolute top-0 right-10 w-20 h-20 bg-emerald-500/20 rounded-full blur-2xl"></div>
      <div className="absolute bottom-10 left-0 w-24 h-24 bg-purple-500/20 rounded-full blur-2xl"></div>
    </div>
  );
}

export default DeviceMockups;
